&lt;p&gt;添加第三方仓库地址 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9wbHVnaW5zLnpoaWxlLmlv&#34;&gt;https://plugins.zhile.io&lt;/span&gt;&lt;br /&gt;
&lt;img data-src=&#34;https://s2.loli.net/2022/06/18/2qiauTbDNrRW4LZ.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;搜索-ide-eval-reset-安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#搜索-ide-eval-reset-安装&#34;&gt;#&lt;/a&gt; 搜索 IDE Eval Reset 安装&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;https://s2.loli.net/2022/06/18/icphvdNyOr5RqK9.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;

 &lt;h2 id=&#34;类模板&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#类模板&#34;&gt;#&lt;/a&gt; 类模板&lt;/h2&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;/**&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; * @description: TODO $&amp;#123;TODO&amp;#125;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; * @author uyume&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; * @date $&amp;#123;DATE&amp;#125; $&amp;#123;TIME&amp;#125;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; * @version #if ($&amp;#123;VERSION&amp;#125; &amp;amp;&amp;amp; $&amp;#123;VERSION&amp;#125; != &#34;&#34;) $&amp;#123;VERSION&amp;#125; #else 0.0.1 #end&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;代码模板&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#代码模板&#34;&gt;#&lt;/a&gt; 代码模板&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.nlark.com/yuque/0/2021/png/2894414/1632377072432-777f7f33-262a-463b-b366-5a9eb55a9fbd.png#crop=0&amp;amp;crop=0&amp;amp;crop=1&amp;amp;crop=1&amp;amp;height=619&amp;amp;id=eMlTA&amp;amp;margin=%5Bobject%20Object%5D&amp;amp;name=image.png&amp;amp;originHeight=1237&amp;amp;originWidth=1599&amp;amp;originalType=binary&amp;amp;ratio=1&amp;amp;rotation=0&amp;amp;showTitle=false&amp;amp;size=191480&amp;amp;status=done&amp;amp;style=none&amp;amp;title=&amp;amp;width=799.5&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 使用方法： /mm + tab&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@author&lt;/span&gt; uyume&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@description&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;//TODO $end$&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@date&lt;/span&gt; $date$ $time$&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@params&lt;/span&gt; $param$&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@return&lt;/span&gt; $&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt;$&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@author&lt;/span&gt; uyume&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@description&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;//TODO $end$&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token annotation punctuation&#34;&gt;@date&lt;/span&gt; $date$ $time$&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.nlark.com/yuque/0/2021/png/2894414/1632377182034-b41ca504-ae9d-4ba2-873a-690c4b84027b.png#crop=0&amp;amp;crop=0&amp;amp;crop=1&amp;amp;crop=1&amp;amp;height=320&amp;amp;id=yuGrZ&amp;amp;margin=%5Bobject%20Object%5D&amp;amp;name=image.png&amp;amp;originHeight=639&amp;amp;originWidth=1085&amp;amp;originalType=binary&amp;amp;ratio=1&amp;amp;rotation=0&amp;amp;showTitle=false&amp;amp;size=56017&amp;amp;status=done&amp;amp;style=none&amp;amp;title=&amp;amp;width=542.5&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
param&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;groovyScript(&amp;quot;
def result = &#39;&#39;;
def params = \&amp;quot;$&amp;#123;_1&amp;#125;\&amp;quot;.replaceAll(&#39;[\\\\[|\\\\]|\\\\s]&#39;, &#39;&#39;);
if (params.trim() == &#39;&#39;) &amp;#123;
	return result;
&amp;#125; else &amp;#123;
	params = params.split(&#39;,&#39;).toList();
  result = params[0];
  for (i = 1; i &amp;lt; params.size; i++) &amp;#123;
  	result += &#39;\\n * @Param &#39; + params[i];
  &amp;#125;;
  return result;
&amp;#125;
&amp;quot;
, methodParameters())
&lt;/code&gt;&lt;/pre&gt;

 &lt;p&gt;#卸载安装的密钥&lt;br /&gt;
 slmgr /upk&lt;/p&gt;
&lt;p&gt;#安装密钥&lt;br /&gt;
 slmgr /ipk&lt;br /&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb2NzLm1pY3Jvc29mdC5jb20vemgtY24vd2luZG93cy1zZXJ2ZXIvZ2V0LXN0YXJ0ZWQva21zLWNsaWVudC1hY3RpdmF0aW9uLWtleXM=&#34;&gt;https://docs.microsoft.com/zh-cn/windows-server/get-started/kms-client-activation-keys&lt;/span&gt;&lt;br /&gt;
2019 lstc M7XTQ-FN8P6-TTKYV-9D4CC-J462D&lt;/p&gt;
&lt;p&gt;#测试 kms 服务商联通性&lt;br /&gt;
 ping &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3poLnVzLnRv&#34;&gt;zh.us.to&lt;/span&gt;&lt;br /&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2ttcy4wM2sub3JnLw==&#34;&gt;kms.03k.org&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;#设置 kms 服务商&lt;br /&gt;
 slmgr /skms &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2ttcy4wM2sub3JnLw==&#34;&gt;kms.03k.org&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;#激活密钥&lt;br /&gt;
 slmgr /ato&lt;/p&gt;
&lt;p&gt;#查看到期时间&lt;br /&gt;
 slmgr –xpr&lt;/p&gt;
&lt;p&gt;#确认激活状态&lt;br /&gt;
 slmgr -dlv&lt;/p&gt;

 &lt;p&gt;#office kms 激活&lt;/p&gt;
&lt;p&gt;#首先 office 版本要为 vol 版&lt;br /&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;&#34;&gt; 2019 转换.bat&lt;/span&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;&#34;&gt;2016 转换.bat&lt;/span&gt;&lt;br /&gt;
 如不是，复制下面批处理转化。&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;@echo off&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:ADMIN&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;openfiles &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;nul &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;nul &lt;span class=&#34;token operator&#34;&gt;||&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; Set UAC &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; CreateObject^&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Shell.Application&#34;&lt;/span&gt;^&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;%temp%\getadmin.vbs&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; UAC.ShellExecute &lt;span class=&#34;token string&#34;&gt;&#34;%~s0&#34;&lt;/span&gt;, &lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;, &lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;, &lt;span class=&#34;token string&#34;&gt;&#34;runas&#34;&lt;/span&gt;, &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;%temp%\getadmin.vbs&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token string&#34;&gt;&#34;%temp%\getadmin.vbs&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;nul &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;&amp;amp;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;goto:eof&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;del /f /q &lt;span class=&#34;token string&#34;&gt;&#34;%temp%\getadmin.vbs&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;nul &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;nul&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; /f &lt;span class=&#34;token string&#34;&gt;&#34;tokens=6 delims=[]. &#34;&lt;/span&gt; %%G &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;ver&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt; &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token assign-left variable&#34;&gt;win&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;%%G&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td d